### Make the lineup tables


::: {.cell}

```{.r .cell-code}
# last five gt
top <- unc_lineups_last_five %>%
  filter(`~Minutes` > 4.9) %>%
  mutate(row_number = 1:n()) %>%
  relocate(row_number, .before = P1) %>%
  gt() %>%
  cols_label(
    # rename columns
    row_number = "",
    P1 = "",
    P2 = "",
    P3 = "",
    P4 = "",
    P5 = ""
  ) %>%
  data_color(
    columns = c(`~Minutes`),
    colors = scales::col_numeric(
      c(
        "#0a4c6a",
                 "#73bfe2",
                 "#cfe8f3",
                 "#fff2cf",
                 "#fdd870",
                 "#fdbf11",
                 "#ca5800"
      ),
      domain = range(5:33)
    )
  ) %>%
  gt_theme_538() %>%
  tab_header(title = md("North Carolina's most used lineups over past _five_ games")) %>%
  tab_source_note(source_note = "@dadgumboxscores | January 19, 2023 | data via stats.ncaa.org") %>%
  tab_options (source_notes.font.size = px(10),
               table.font.size = px(10),)

# save image
gtsave_extra(top,
             "top_l.png",
             vwidth = 650,
             vheight = 650)

# all other lineups
bot <- unc_lineups_last_five %>%
  filter(`~Minutes` < 5.0) %>%
  mutate(row_number = 1:n()) %>%
  relocate(row_number, .before = P1) %>%
  gt() %>%
  cols_label(
    # rename columns
    row_number = "",
    P1 = "",
    P2 = "",
    P3 = "",
    P4 = "",
    P5 = ""
  ) %>%
  data_color(
    columns = c(`~Minutes`),
    colors = scales::col_numeric(
      c(
        "#0a4c6a",
                 "#73bfe2",
                 "#cfe8f3",
                 "#fff2cf",
                 "#fdd870",
                 "#fdbf11",
                 "#ca5800"
      ),
      domain = range(0:5)
    )
  ) %>%
  gt_theme_dot_matrix() %>%
  tab_header(title = md("North Carolina's _infrequent_ lineups over past _five_ games")) %>%
  tab_source_note(source_note = "@dadgumboxscores | January 19, 2023 | data via stats.ncaa.org") %>%
  tab_options (
    source_notes.font.size = px(10),
    row.striping.background_color = '#d0e4f3',
    table.font.size = px(10),
    column_labels.text_transform = 'capitalize'
  )

gtsave_extra(bot,
             "bot_l.png",
             vwidth = 650,
             vheight = 650)

top
```

